    "contact-cta-title": { en: "Ready to Explore Kurdistan?", ku: "ئامادەیت بۆ گەشتی کوردستان؟", ar: "مستعد لاستكشاف كردستان؟" },
    "contact-cta-sub": { en: "Start planning your adventure to one of the Middle East's most beautiful regions", ku: "دەستبکە بە پلاندانان بۆ ماجەراکەت بۆ یەکێک لە جوانترین ناوچەکانی ڕۆژهەڵاتی ناوەڕاست", ar: "ابدأ التخطيط لمغامرتك إلى واحدة من أجمل مناطق الشرق الأوسط" },
    "btn-view-gallery": { en: "View Gallery", ku: "گەلەری ببینە", ar: "مشاهدة المعرض" },
