    "send-message": { en: "Send Us a Message", ku: "پەیامێکمان بۆ بنێرە", ar: "أرسل لنا رسالة" },
    "send-message-sub": { en: "Fill out the form below and we'll get back to you soon", ku: "فۆڕمەکەی خوارەوە پڕ بکەرەوە و بە زووانە وەڵامت دەدەینەوە", ar: "املأ النموذج أدناه وسنرد عليك قريباً" },
